const amqp = require('amqplib');
const { Pool } = require('pg');

const rabbitmqUrl = process.env.RABBITMQ_URL || 'amqp://localhost';
const databaseUrl = process.env.DATABASE_URL || 'postgresql://user:pass@localhost/db';

const connection = amqp.connect(rabbitmqUrl);
const pool = new Pool({ connectionString: databaseUrl });

const messageHandlers = {
  createUser: async (data) => {
    const query = 'INSERT INTO users(name, email) VALUES($1, $2) RETURNING id';
    const values = [data.name, data.email];
    return await pool.query(query, values);
  },
  updateUser: async (data) => {
    const query = 'UPDATE users SET name = $1, email = $2 WHERE id = $3';
    const values = [data.name, data.email, data.id];
    return await pool.query(query, values);
  },
  deleteUser: async (data) => {
    const query = 'DELETE FROM users WHERE id = $1';
    const values = [data.id];
    return await pool.query(query, values);
  }
};

const validateMessage = (message) => {
  if (!message || typeof message !== 'object') {
    throw new Error('Invalid message format');
  }
  
  if (!message.type || typeof message.type !== 'string') {
    throw new Error('Message must have a valid type');
  }
  
  if (!message.payload || typeof message.payload !== 'object') {
    throw new Error('Message must have a valid payload');
  }
  
  const allowedTypes = ['createUser', 'updateUser', 'deleteUser'];
  if (!allowedTypes.includes(message.type)) {
    throw new Error('Unsupported message type');
  }
  
  return true;
};

const processMessage = async (msg) => {
  try {
    const message = JSON.parse(msg.content.toString());
    
    validateMessage(message);
    
    const handler = messageHandlers[message.type];
    if (!handler) {
      throw new Error(`No handler for message type: ${message.type}`);
    }
    
    const result = await handler(message.payload);
    
    console.log(`Processed message type: ${message.type}`, result);
    
    channel.ack(msg);
  } catch (error) {
    console.error('Error processing message:', error.message);
    channel.nack(msg, false, false);
  }
};

const startMicroservice = async () => {
  try {
    const conn = await connection;
    const channel = await conn.createChannel();
    
    const queue = 'event_queue';
    await channel.assertQueue(queue, { durable: true });
    channel.prefetch(1);
    
    channel.consume(queue, processMessage, { noAck: false });
    
    console.log('Microservice started and listening for messages...');
  } catch (error) {
    console.error('Failed to start microservice:', error);
    process.exit(1);
  }
};

startMicroservice();